#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 1: modelo congelado + oraculo L4 + vectores dorados
# Entrega autocontenida. Validacion sin dependencias (Python 3 puro).
# Linea esperada al final:
# NPU PASO1 OK ORACULO SIG=0xB080DFF1 MUTACIONES 5/5 FAIL
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
mkdir -p "$DIR/model" "$DIR/oracle"
base64 -d << "EOF" > "$DIR/model/train_and_freeze.py"

EOF
base64 -d << "EOF" > "$DIR/oracle/oracle_npu.py"

EOF
base64 -d << "EOF" > "$DIR/model/npu_weights.hex"

EOF
base64 -d << "EOF" > "$DIR/model/npu_golden.txt"

EOF
cd "$DIR"
L=$(python3 oracle/oracle_npu.py model/npu_weights.hex model/npu_golden.txt) || { echo "FALLO: $L"; exit 1; }
SIG=$(echo "$L" | sed 's/.*SIG=\(0x[0-9A-F]*\).*/\1/')
NF=0
for m in 1 2 3 4 5; do
  if NPU_MUT=$m python3 oracle/oracle_npu.py model/npu_weights.hex model/npu_golden.txt > /dev/null 2>&1; then
    echo "FALLO: mutacion $m NO fallo"; exit 1
  else
    NF=$((NF+1))
  fi
done
echo "NPU PASO1 OK ORACULO SIG=$SIG MUTACIONES $NF/5 FAIL"
)
